// Deterministische Validierung – niemals dem LLM überlassen.
const input = $input.first().json || {};
const src = (input.query && typeof input.query === 'object') ? input.query : input;

const name = String(src.name ?? '').trim();
const email = String(src.email ?? '').trim();
const phone = String(src.phone ?? '').trim();
const topic = String(src.topic ?? '').trim();
const rawStart = String(src.startISO ?? '').trim();

const TZ = 'Europe/Berlin';
const now = $now.setZone(TZ);
const problems = [];

if (!name) problems.push('Name fehlt');
if (!email && !phone) problems.push('E-Mail oder Telefonnummer fehlt');
if (email && !/^[^@\s]+@[^@\s]+\.[^@\s]+$/.test(email)) problems.push('E-Mail ungültig');

let start = DateTime.fromISO(rawStart, { zone: TZ });
if (!start.isValid) start = DateTime.fromISO(rawStart).setZone(TZ);
if (!rawStart || !start.isValid) problems.push('Startdatum ungültig');

if (problems.length === 0) {
  if (start < now.plus({ minutes: 60 })) problems.push('Termin zu kurzfristig oder in der Vergangenheit');
  if (start > now.plus({ days: 180 })) problems.push('Termin zu weit in der Zukunft');
}

if (problems.length > 0) {
  return [{ json: {
    valid: false,
    action: 'invalid',
    response: {
      ok: false,
      error: 'invalid_input',
      message: 'Bitte nennen Sie einen gültigen Namen, eine Kontaktmöglichkeit (E-Mail oder Telefon) und einen konkreten Wunschtermin mit Datum und Uhrzeit.',
      problems,
    },
  }}];
}

const end = start.plus({ minutes: 30 });
return [{ json: {
  valid: true,
  name, email, phone, topic,
  startISO: start.toISO(),
  endISO: end.toISO(),
  startLabel: start.setLocale('de').toFormat("cccc, dd.LL.yyyy, HH:mm") + ' Uhr',
  windowMinISO: now.toISO(),
  windowMaxISO: start.plus({ days: 14 }).toISO(),
  tz: TZ,
}}];

// Verfügbarkeit prüfen, Doppelbuchung erkennen, Alternativen deterministisch berechnen.
const v = $('Validate & Normalize').first().json;
const TZ = v.tz || 'Europe/Berlin';
const reqStart = DateTime.fromISO(v.startISO).setZone(TZ);
const reqEnd = DateTime.fromISO(v.endISO).setZone(TZ);
const overlaps = (aS, aE, bS, bE) => aS < bE && bS < aE;

// Kalender-Events aus dem Fenster einsammeln (Get Events liefert bei leer ein {}).
const events = [];
for (const item of $input.all()) {
  const e = item.json || {};
  const s = e.start && (e.start.dateTime || e.start.date);
  const en = e.end && (e.end.dateTime || e.end.date);
  if (!s || !en) continue;
  if (e.status === 'cancelled') continue;
  const es = DateTime.fromISO(s).setZone(TZ);
  const ee = DateTime.fromISO(en).setZone(TZ);
  if (!es.isValid || !ee.isValid) continue;
  const attendees = Array.isArray(e.attendees) ? e.attendees.map(a => a.email || '').join(' ') : '';
  const text = ((e.summary || '') + ' ' + (e.description || '') + ' ' + attendees).toLowerCase();
  events.push({ es, ee, text });
}

const email = (v.email || '').toLowerCase();
const slotEvents = events.filter(ev => overlaps(reqStart, reqEnd, ev.es, ev.ee));

// Dedupe: identischer Lead im selben Slot -> nicht doppelt buchen.
if (email && slotEvents.some(ev => ev.text.includes(email))) {
  return [{ json: { action: 'already', response: {
    ok: true, alreadyBooked: true, label: v.startLabel,
    message: 'Für diese E-Mail besteht zu diesem Zeitpunkt bereits ein Termin.',
  }}}];
}

// Slot frei -> anlegen.
if (slotEvents.length === 0) {
  return [{ json: { action: 'create', ...v } }];
}

// Slot belegt -> bis zu 3 freie Alternativen (30-Min-Raster, Mo–Fr 8–18) berechnen.
const now = $now.setZone(TZ);
let cursor = (reqStart > now.plus({ minutes: 60 }) ? reqStart : now.plus({ minutes: 60 }))
  .set({ second: 0, millisecond: 0 });
const m = cursor.minute;
if (m > 0 && m < 30) cursor = cursor.set({ minute: 30 });
else if (m > 30) cursor = cursor.plus({ hours: 1 }).set({ minute: 0 });

const limit = reqStart.plus({ days: 14 });
const alternatives = [];
let guard = 0;
while (alternatives.length < 3 && cursor < limit && guard < 3000) {
  guard++;
  const wd = cursor.weekday; // 1=Mo .. 7=So
  const h = cursor.hour + cursor.minute / 60;
  const inHours = wd >= 1 && wd <= 5 && h >= 8 && h + 0.5 <= 18;
  if (inHours) {
    const cEnd = cursor.plus({ minutes: 30 });
    const busy = events.some(ev => overlaps(cursor, cEnd, ev.es, ev.ee));
    if (!busy) {
      alternatives.push({
        startISO: cursor.toISO(),
        label: cursor.setLocale('de').toFormat("cccc, dd.LL.yyyy, HH:mm") + ' Uhr',
      });
    }
  }
  cursor = cursor.plus({ minutes: 30 });
}

return [{ json: { action: 'alternatives', response: {
  ok: false, reason: 'busy',
  message: 'Der gewünschte Termin ist leider belegt. Hier sind freie Alternativen:',
  alternatives,
}}}];
